  margin: 0 auto;
  padding: 3rem 1.5rem 5rem;
}

/* ── HERO ── */
.hero {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 3.5rem;
  padding-bottom: 3rem;
}

