  width: 160px;
  height: 160px;
  border-radius: 50%;
  object-fit: cover;
  display: block;
  flex-shrink: 0;
}

.headshot-icons {
  display: flex;
  flex-direction: column;
  gap: 12px;
  padding-top: 10px;
}

.icon-link {
  display: block;
  line-height: 1;
  color: #D4537E;
}
.icon-link:hover { opacity: 0.65; }

.hero-headline {
  font-size: 1.75rem;
  font-weight: 700;
  line-height: 1.4;
  color: var(--text);
  margin: 0 0 1rem;
}

.accent { color: var(--accent); }

.hero-bio {
  color: #5a5a5a;
  font-size: 0.95rem;
  line-height: 1.75;
  margin: 0 0 1.75rem;
}

.cta-row {
  display: flex;
