  font-weight: 500;
  border-radius: 4px;
  text-decoration: none;
}
.btn:hover { opacity: 0.82; text-decoration: none; }

.btn-primary {
  background: var(--accent);
  color: #fff;
  border: 1px solid var(--accent);
}

.btn-outline {
  background: transparent;
  color: var(--accent);
  border: 1px solid var(--accent);
}

/* Stat grid */
.stat-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 1rem;
  margin-bottom: 1.25rem;
}

.stat-box {
  border: 1px solid var(--border);
  border-radius: 4px;
  padding: 1.1rem 1.25rem;
}

.stat-number {
  display: block;
  font-size: 1.6rem;
  font-weight: 700;
  color: var(--text);
  line-height: 1.2;
}

.stat-label {
  display: block;
  font-size: 0.72rem;
  text-transform: uppercase;
  letter-spacing: 0.1em;
  color: var(--muted);
  margin-top: 0.25rem;
  line-height: 1.4;
}

/* Skill chips */
.chip-row {
  display: flex;
  flex-wrap: wrap;
  gap: 0.4rem;
}

.chip {
  border: 1px solid var(--accent);
  color: var(--accent);
  background: transparent;
  font-size: 0.78rem;
  padding: 0.22rem 0.75rem;
  border-radius: 999px;
  white-space: nowrap;
}

/* ── DIVIDER ── */
.section-hr {
  border: none;
  border-top: 1px solid var(--border);
  margin: 3rem 0;
}

