.section-label {
  font-size: 11px;
  text-transform: uppercase;
  letter-spacing: 0.15em;
  color: var(--muted);
  font-weight: 600;
  margin: 0 0 1.75rem;
}

/* ── TIMELINE ── */
.timeline-entry {
  display: grid;
  grid-template-columns: 140px 1fr;
  gap: 1.75rem;
  margin-bottom: 2.25rem;
}

.tl-date {
  font-size: 0.78rem;
  color: var(--muted);
  line-height: 1.6;
  padding-top: 0.15rem;
}

.tl-role {
  font-size: 0.95rem;
  font-weight: 600;
  color: var(--text);
  margin: 0 0 0.15rem;
}

.tl-org {
  font-size: 0.85rem;
  color: var(--accent);
  margin: 0 0 0.5rem;
}

.tl-desc {
  font-size: 0.875rem;
  color: #5a5a5a;
  line-height: 1.65;
  margin: 0;
}

/* ── NOW CARD ── */
.now-card {
  border: 1px solid var(--border);
  border-radius: 4px;
  padding: 1.5rem;
}

.now-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 0.75rem;
}

.now-live {
  display: flex;
  align-items: center;
  gap: 0.4rem;
}

.live-dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background: var(--accent);
  display: inline-block;
  animation: pulse 2s infinite;
}

@keyframes pulse {
  0%, 100% { opacity: 1; }
  50% { opacity: 0.4; }
}

.live-label {
  font-size: 10px;
  text-transform: uppercase;
  letter-spacing: 0.12em;
  color: var(--accent);
  font-weight: 700;
}

.now-date-badge {
  font-size: 0.75rem;
  color: var(--muted);
  border: 1px solid var(--border);
  padding: 0.15rem 0.65rem;
  border-radius: 999px;
}

.now-project {
  font-size: 1.05rem;
  font-weight: 700;
  color: var(--text);
  margin-bottom: 0.2rem;
}

.now-subtitle {
  font-size: 0.8rem;
  color: var(--accent);
  margin-bottom: 1.25rem;
}

.now-fields {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 1.25rem;
  margin-bottom: 1.25rem;
}

.now-field-label {
  display: block;
  font-size: 10px;
  text-transform: uppercase;
  letter-spacing: 0.12em;
  color: var(--muted);
  font-weight: 600;
  margin-bottom: 0.3rem;
}

.now-field-value {
  font-size: 0.82rem;
  color: #5a5a5a;
  line-height: 1.6;
}

.now-tags {
  display: flex;
  flex-wrap: wrap;
  gap: 0.35rem;
}

.now-tag {
  font-size: 0.75rem;
  padding: 0.2rem 0.65rem;
  border-radius: 999px;
  border: 1px solid var(--border);
  color: var(--muted);
  background: transparent;
}

.now-tag.accent-tag {
  border-color: var(--accent);
  color: var(--accent);
}

/* ── ARCHIVE TABLE ── */
.archive-table {
  width: 100%;
  border-collapse: collapse;
}

.archive-table th {
  font-size: 10px;
  text-transform: uppercase;
  letter-spacing: 0.12em;
  color: var(--muted);
  font-weight: 600;
  text-align: left;
  padding: 0.6rem 1rem 0.6rem 0;
  border-bottom: 1px solid var(--border);
}

.archive-table td {
  padding: 0.7rem 1rem 0.7rem 0;
  border-bottom: 1px solid var(--border);
  color: var(--text);
  font-size: 0.875rem;
}

.archive-table .archive-tags {
  color: var(--muted);
  font-size: 0.8rem;
}

.scroll-cue {
  display: flex;
  justify-content: center;
  margin-top: 0.5rem;
  margin-bottom: 2.5rem;
}

.scroll-cue a {
  width: 54px;
  height: 54px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
