  animation: bounce-down 1.8s infinite;
}

.scroll-cue a:hover {
  opacity: 1;
  transform: translateY(2px);
  box-shadow: 0 8px 20px rgba(212, 83, 126, 0.24);
}

.scroll-cue svg {
  width: 24px;
  height: 24px;
}

